#include <cstdio>
#include <cstdlib>

#define N 15

int board[N][N];

bool isSafe(int row, int col) {
  for (int i = 0; i < col; i++)
    if (board[row][i])
      return false;

  for (int i = row, j = col; i >= 0 && j >= 0; i--, j--)
    if (board[i][j])
      return false;

  for (int i = row, j = col; j >= 0 && i < N; i++, j--)
    if (board[i][j])
      return false;

  return true;
}

int main() {
  int solutions = 0;

  #pragma omp target data map(tofrom: board) map(tofrom: solutions)
  {
    #pragma omp target teams distribute parallel for thread_limit(256)
    for (int i = 0; i < N; i++) {
      int local_board[N][N] = {0};
      int local_solutions = 0;
      local_board[i][0] = 1;

      // Copy local_board to global board for isSafe usage
      for (int r = 0; r < N; r++)
        for (int c = 0; c < N; c++)
          board[r][c] = local_board[r][c];

      struct StackFrame {
        int row;
        int col;
      };

      StackFrame stack[N];
      int top = 0;
      stack[top].col = 1;
      stack[top].row = 0;

      while (top >= 0) {
        int col = stack[top].col;
        int row = stack[top].row;

        bool found = false;
        while (row < N) {
          if (isSafe(row, col)) {
            board[row][col] = 1;
            top++;
            if (col + 1 == N) {
              local_solutions++;
              board[row][col] = 0;
              row++;
            } else {
              stack[top].col = col + 1;
              stack[top].row = 0;
              found = true;
              break;
            }
          } else {
            row++;
          }
        }
        if (!found) {
          top--;
          if (top >= 0) {
            int prev_col = stack[top].col;
            int prev_row = stack[top].row;
            board[prev_row][prev_col] = 0;
            stack[top].row = prev_row + 1;
          }
        }
      }

      #pragma omp atomic
      solutions += local_solutions;
    }
  }

  printf("Total solutions for %d-Queens: %d\n", N, solutions);
  return 0;
}
